import{_ as i,o as t,c as n,ag as a}from"./chunks/framework.DXGyWiRo.js";const r="/images/lekt1501.jpg",p="/images/lekt1503.jpg",l="/images/lekt1502.jpg",s="/images/lekt1504.jpg",o="/images/lekt1505.jpg",u="/images/lekt1506.jpg",d="/images/lekt1507.jpg",m="/images/lekt1508.jpg",h="/images/lekt1509.jpg",w=JSON.parse('{"title":"Lektion 15","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion15.md","filePath":"lektionen/lektion15.md"}'),g={name:"lektionen/lektion15.md"};function c(b,e,k,q,v,f){return t(),n("div",null,[...e[0]||(e[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-15" tabindex="-1">Lektion 15 <a class="header-anchor" href="#lektion-15" aria-label="Permalink to &quot;Lektion 15&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>१. सुभाषितम्</li><li>15.2. Determinativkomposita = Tatpuruṣa m. = तत्पुरुष</li><li>15.3. Determinativkomposita mit attributivem / appositionellem Vorderglied = Karmadhāraya m. = कर्मधारय</li><li>15.4. Determinativkomposita mit einem Vorderglied, das zum Hinterglied in einem nicht-attributiv/appositionellem Kasusverhältnis steht = Tatpuruṣa im engeren Sinn</li><li>15.5. Zerlegung von Komposita (außer Dvandvas)</li><li>15.6. Die Form des Vorderglieds in Komposita (समास m.)</li><li>15.7. Einteilung der तत्पुरुष <ul><li>15.7.1. Einteilung der कर्मधारय</li></ul></li><li>15.8. Wortliste</li><li>15.9. Übung 1</li><li>15.10. Übung 2</li><li>15.11. Übung 3</li></ul><h2 id="१-सुभाषितम्" tabindex="-1">१. सुभाषितम् <a class="header-anchor" href="#१-सुभाषितम्" aria-label="Permalink to &quot;१. सुभाषितम्&quot;">​</a></h2><blockquote><p>गुरुशुश्रूषया विद्या<br> पुष्कलेन धनेन वा ।<br> अथवा विद्यया विद्या<br> चतुर्थी नैव विद्यते ॥</p></blockquote><h2 id="_15-2-determinativkomposita-tatpurusa-m-तत्पुरुष" tabindex="-1">15.2. Determinativkomposita = Tatpuruṣa m. = तत्पुरुष <a class="header-anchor" href="#_15-2-determinativkomposita-tatpurusa-m-तत्पुरुष" aria-label="Permalink to &quot;15.2. Determinativkomposita = Tatpuruṣa m. = तत्पुरुष&quot;">​</a></h2><p>Das Verhältnis von durch Nomina (Substantive und Adjektive) Bezeichnetem zueinander kann man außer durch eine Genetivkonstruktion auch durch ein Tatpuruṣa (तत्पुरुष) ausdrücken. Ebenso kann man attributive Beiordnungen von Adjektiven oder appositionelle Beiordnung von Substantiven durch eine bestimmte Art von Tatpuruṣa, nämlich durch sog. Karmadhāraya (m.) = कर्मधारय ausdrücken.</p><p>तत्पुरुषः =  तस्य पुरुषः &quot;sein Knecht&quot;, d.h. als Bezeichnung dieser Art von Komposita dient ein Beispiel solcher Komposita.</p><p>In determinativen Komposita (Tatpuruṣa) wird ein Nomen (Substantiv oder Adjektiv)  durch ein anderes Nomen oder Adverb näher bestimmt. Das näher bestimmte Wort bildet in der Regel das Hinterglied des Kompositum.</p><p>Das Verhältnis der Vorderglieds (determinierendes Glied) zum Hinterglied (determiniertes Glied) kann sein:</p><ul><li>attributiv bzw. appositionell: bei Auflösung des Kompositums bildet das Vorderglied zum Hinterglied eine nähere Bestimmung im selben Kasus (d.h. außerhalb eines Satzzusammenhangs im Nominativ (प्रथमा), im Satz im syntaktisch geforderten Kasus)</li><li>kasuell: das Vorderglied steht bei der Auflösung der Kompositums in einem anderen Kasus als das Hinterglied (d.h. nicht im Nominativ - प्रथमा)</li><li>adverbial: das Vorderglied ist ein nicht-deklinierbares Wort</li></ul><p>Das Kasusverhältnis beider Glieder eines Kompositums ist unabhängig davon, in welchem Kasus das Kompositum steht: das Kompositum ist ja ein einziges deklinierbares Wort:</p><p>z. B.</p><blockquote><p>Nom. sg. तत्पुरुषः = तस्य पुरुषः<br> Akk. sg. तत्पुरुषम् = तस्य पुरुषम्<br> Instr. sg. तत्पुरुषेण = तस्य पुरुषेण<br> Gen. sg. तत्पुरुषस्य = तस्य पुरुषस्य<br> Nom. pl. तत्पुरुषाः = तस्य पुरुषाः<br> usw.</p></blockquote><p>Das Geschlecht eines Tatpuruṣa ist - mit wenigen Ausnahmen - das seines Hintergliedes.</p><h2 id="_15-3-determinativkomposita-mit-attributivem-appositionellem-vorderglied-karmadharaya-m-कर्मधारय" tabindex="-1">15.3. Determinativkomposita mit attributivem / appositionellem Vorderglied = Karmadhāraya m. = कर्मधारय <a class="header-anchor" href="#_15-3-determinativkomposita-mit-attributivem-appositionellem-vorderglied-karmadharaya-m-कर्मधारय" aria-label="Permalink to &quot;15.3. Determinativkomposita mit attributivem / appositionellem Vorderglied = Karmadhāraya m. = कर्मधारय&quot;">​</a></h2><p>Bei Auflösung des Karmadhāraya stehen beide Glieder des Kompositums im selben Kasus.</p><p>z.B.</p><blockquote><p>गुणवत्पुत्रः = गुणवान्पुत्रः = &quot;ein Sohn mit guten Eigenschaften&quot;</p><blockquote><p>Akk. sg. गुणवत्पुत्रम्<br> Nom pl. गुणवत्पुत्राः</p></blockquote><p>पुण्यवत्क्षत्रिया = पुण्यवती क्षत्रिया = &quot;eine verdienstreiche Kṣatriyafrau&quot;</p><p>साधुजनाः = साधवो जनाः = &quot;gute Leute&quot;</p><p>इष्टदेवता = इष्टा देवता = &quot;die gewünschte Gottheit = die Gottheit, zu der man ein besonderes Andachts- und Zufluchtsverhältnis hat&quot;</p><p><img src="'+r+'" alt=""><br> Abb.: लक्ष्मी, die Göttin des Wohlstandes, eine इष्टदेवता mancher Inder<br> Gemälde von राजा रवि वर्मा (1848 - 1906)<br> [Bildquelle: Wikipedia, Public domain]</p></blockquote><p>Zur Abfolge der Glieder in einem Karmadhāraya ist folgende Sonderregel zu beachten:</p><ul><li><p>drückt ein Karmadhāraya einen VERGLEICH aus, dann steht das, womit verglichen wird, im Hinterglied des Kompositums:</p><p>नरसिंहः = सिंह इव नरः = &quot;ein Mann wie ein Löwe&quot;पुरुषव्याघ्रः = व्याघ्र इव पुरुषः = &quot;ein Mann wie ein Tiger&quot;</p></li><li><p>drückt ein Karmadhāraya aber eine Apposition (nähere Bestimmung des Hinterglieds durch ein Substantiv) aus, so steht das näher Bestimmende im Vorderglied, wie es auch die allgemeine Regel für die Reihenfolge für die Glieder in einem Tatpuruṣa fordert:</p><p>नरसिंहः  kann auch aufgelöst werden: नर एव सिंहः = &quot;Ein Löwe, der (in Wirklichkeit) ein Mann ist.</p><p>Solche appositionelle Karmadhāraya werden in den einheimischen Kommentaren wie im obigen Beispiel mittels एव aufgelöst.</p></li></ul><p><img src="'+p+'" alt=""><br> Abb.:  नरसिंह, ein अवतार Viṣṇus<br> Belur (ಬೇಲೂರು), Karnataka (ಕರ್ನಾಟಕ)<br> [Bildquelle: Wikipedia, Public domain]</p><h2 id="_15-4-determinativkomposita-mit-einem-vorderglied-das-zum-hinterglied-in-einem-nicht-attributiv-appositionellem-kasusverhaltnis-steht-tatpurusa-im-engeren-sinn" tabindex="-1">15.4. Determinativkomposita mit einem Vorderglied, das zum Hinterglied in einem nicht-attributiv/appositionellem Kasusverhältnis steht = Tatpuruṣa im engeren Sinn <a class="header-anchor" href="#_15-4-determinativkomposita-mit-einem-vorderglied-das-zum-hinterglied-in-einem-nicht-attributiv-appositionellem-kasusverhaltnis-steht-tatpurusa-im-engeren-sinn" aria-label="Permalink to &quot;15.4. Determinativkomposita mit einem Vorderglied, das zum Hinterglied in einem nicht-attributiv/appositionellem Kasusverhältnis steht = Tatpuruṣa im engeren Sinn&quot;">​</a></h2><p>Tatpuruṣaverbindungen sind möglich für Verbindungen von Nomina (Substantive und Adjektive), bei denen das Vorderglied - den Regeln der Syntax entsprechend - in jedem Kasus stehen kann. Erwartungsgemäß vertritt das Vorderglied am häufigsten einen Genetiv (षष्ठी), da dies ja der Kasus ist, um das Verhältnis von Nomina auszudrücken.</p><p>z.B.</p><blockquote><p>क्षत्रियपुत्रः = क्षत्रियस्य पुत्रः = &quot;der Sohn eines Kṣatriya&quot;, &quot;ein junger Kṣatriya&quot;, &quot;ein  Angehöriger der Gruppe der Kṣatriyas&quot;</p><blockquote><p>Akk. sg. क्षत्रियपुत्रम्<br> Gen. sg. क्षत्रियपुत्रस्य<br> u.s.w.</p></blockquote><p>गुरुभावः =  गुरोर्भावः  = &quot;die Natur eines Lehrers&quot;</p><p>धनलोभः = धनस्य लोभः = &quot;Begierde nach Reichtum, Habsucht&quot;</p><p>लोकगतिः = लोकस्य गतिः = &quot;der Gang der Welt, das Verhalten der Leute&quot;</p></blockquote><p>Fast jedes Genetivverhältnis kann durch ein Tatpuruṣa ersetzt werden. Die Wenigen Ausnahmen siehe z.B. bei Kale, A higher Sanskrit grammar § 211, dort auch die entsprechenden Stellen bei Pāṇini.</p><p>Das Vorderglied eines Tatpuruṣa kann aber prinzipiell jeden Kasus vertreten. Allerdings können nicht alle syntaktisch möglichen Kasusverhältnisse durch ein Tatpuruṣa ersetzt werden. Die entsprechenden regeln findet man im Zweifelsfall bei Kale, A higher Sanskrit grammar § 203 - 217 bzw. Pāṇini 2,1,22 - 2,2,22.</p><p>Das Vorderglied kann bei der Auflösung des Kompositums im Singular, Dual oder Plural stehen. Welche Möglichkeit vorliegt, muss aus Bedeutung und Kontext erschlossen werden.</p><p>Beispiele:</p><p>Das Vorderglied vertritt den Akkusativ (द्वितीया): z.B. bei gewissen PPP zu Verben der Bewegung (Pāṇini 2,1,24):</p><blockquote><p>ग्रामगतः = ग्रामं गतः = &quot;einer, der ins Dorf gegangen ist&quot;<br> नरकपतिता = नरकं पतिता = &quot;eine, die in eine Hölle gefallen ist&quot;</p></blockquote><p>Das Vorderglied vertritt den Instrumentalis (तृतीया): z.B. häufig der Agens (कर्तृ) von Nominalbildungen mit kṛt-Suffixen (z.B. PPP):</p><blockquote><p>देवकृतम् = देवेन / देवैः कृतम् = &quot;von einem Gott / von Göttern gemacht&quot;<br> Wäre auch auflösbar: देवस्य / देवानां कृतम् = &quot;Tat / Tun eines Gottes / von Göttern ; Gottestat, Göttertat&quot;</p><p>बुद्धरक्षिता  = बुद्धेन रक्षिता = &quot;die, die von Buddha behütet wurde&quot; (ein Eigenname)</p></blockquote><h2 id="_15-5-zerlegung-von-komposita-außer-dvandvas" tabindex="-1">15.5. Zerlegung von Komposita (außer Dvandvas) <a class="header-anchor" href="#_15-5-zerlegung-von-komposita-außer-dvandvas" aria-label="Permalink to &quot;15.5. Zerlegung von Komposita (außer Dvandvas)&quot;">​</a></h2><p>Obwohl im Sanskrit Komposita beliebiger Länge gebildet werden können und auch sehr häufig gebildet werden (Komposita aus 10 bis 30 Gliedern sind keine Seltenheit!), so sind doch - mit Ausnahme der Dvandvas - alle Komposita fortschreitend hierarchisch in je zwei Teile zu zerlegen:</p><p><img src="'+l+'" alt=""></p><p>u.s.w. bis man zu den einzelnen Wortstämmen kommt.</p><p>z.B.</p><p>गुणवत्पुत्रकृतपुण्यम्</p><blockquote><p>1. Stufe (Hauptzäsur): गुणवत्पुत्रकृतं ॥१॥ पुण्यम्</p><p>2. Stufe (1. Nebenzäsur): गुणवत्पुत्रेण ॥२॥ कृतं ॥१॥ पुण्यम्</p><p>3. Stufe (2. Nebenzäsur): गुणवता॥३॥ पुत्रेण ॥२॥ कृतं ॥१॥ पुण्यम्</p><p>= &quot;die verdienstvolle Tat (das Verdienst), die mein tugendhafter Sohn getan hat&quot;</p></blockquote><p>Dabei können verschiedene Arten von Komposita gemischt werden, z.B. Vorderglied: Bahuvrīhi (बहुव्रीहि) - Hinterglied: Tatpuruṣa usw.</p><p>z.B.</p><p>ब्राह्मणक्षत्रियवैश्यधर्मः</p><blockquote><p>1. Stufe: ब्राह्मणक्षत्रियवश्यानां धर्मः (Vorderglied: Itaretaradvandva)</p><p>2. Stufe: ब्राह्मणानां क्षत्रियाणां वैश्यानां च धर्मः</p><p>= &quot;der Dharma von Brahmanen, Kṣatriyas und Vaiśyas&quot;</p></blockquote><p>Sehr oft gibt es für ein Kompositum verschiedene Möglichkeiten der Auflösung. Welches die richtige oder zumindest die beste ist, kann nur aus dem Kontext und dem Inhalt des Textes entschieden werden. Manchmal ist eine solche Entscheidung nicht möglich. Oft sind zwei Auflösungsmöglichkeiten vermutlich vom Autor intendiert. Dann muss man in der Übersetzung beide Auflösungsmöglichkeiten wiedergeben (verbunden mit &quot;und&quot;, &quot;oder&quot; &quot;bzw.&quot; und dergleichen.</p><p>z.B.</p><p>पुण्यवत्पुत्रकृतम्</p><blockquote><p>1. Stufe: entweder - oder</p><ol><li><p>पुण्यवत्पुत्रेण कृतम्</p></li><li><p>पुण्यवत्पुत्रस्य कृतम्</p></li><li><p>पुण्यवत् पुत्रकृतम्</p></li></ol><p>2. Stufe: entsprechend</p><ol><li><p>पुण्यवता पुत्रेण कृतम् = &quot;das von meinem verdienstreichen Sohn Getane&quot;</p></li><li><p>पुण्यवतः पुत्रस्य कृतम् = &quot;die Tat meines verdienstreichen Sohnes&quot;</p></li><li><ol><li><p>पुण्यवत् पुत्रेण कृतम् = &quot;das verdienstvolle, von meinem Sohn Getane&quot;</p></li><li><p>पुण्यवत् पुत्रस्य कृतम् = &quot;die verdienstvolle Tat meines Sohnes&quot;</p></li></ol></li></ol></blockquote><h2 id="_15-6-die-form-des-vorderglieds-in-komposita-समास-m" tabindex="-1">15.6. Die Form des Vorderglieds in Komposita (समास m.) <a class="header-anchor" href="#_15-6-die-form-des-vorderglieds-in-komposita-समास-m" aria-label="Permalink to &quot;15.6. Die Form des Vorderglieds in Komposita (समास m.)&quot;">​</a></h2><p>In allen Arten von Komposita ist das Vorderglied in der Regel der unveränderte Wortstamm. Zweistämmige Nomina stehen im schwachen Stamm. Feminine Adjektive, die ein folgendes Glied im Kompositum näher bestimmen, stehen im Allgemeinen in maskulinen Stamm:</p><p>z.B.</p><p>पुण्यवत्क्षत्रिया =  पुण्यवती क्षत्रिया = &quot;eine Kṣatriyafrau, die Verdienst besitzt&quot;<br> गुणवत्पुत्रः = गुणवान् पुत्रः = &quot;ein Sohn mit guten Eigenschaften&quot;</p><h2 id="_15-7-einteilung-der-तत्पुरुष" tabindex="-1">15.7. Einteilung der तत्पुरुष <a class="header-anchor" href="#_15-7-einteilung-der-तत्पुरुष" aria-label="Permalink to &quot;15.7. Einteilung der तत्पुरुष&quot;">​</a></h2><ol><li>प्रथमातत्पुरुषः : Vorderglied steht in विग्रहवाक्य im Nominativ (प्रथमा)</li><li>द्वितीयातत्पुरुषः : Vorderglied steht in विग्रहवाक्य im Akkusativ (द्वितीया)</li><li>तृतीयातत्पुरुषः : Vorderglied steht in विग्रहवाक्य im Instrumentalis (तृतीया)</li><li>चतुर्थीतत्पुरुषः : Vorderglied steht in विग्रहवाक्य im Dativ (चतुर्थी)</li><li>पञ्चमीतत्पुरुषः : Vorderglied steht in विग्रहवाक्य im Ablativ (पज्चमी)</li><li>षष्ठीतत्पुरुषः : Vorderglied steht in विग्रहवाक्य im Genetiv (षष्ठी)</li><li>सप्तमीतत्पुरुषः : Vorderglied steht in विग्रहवाक्य im Lokativ (सप्तमी)</li></ol><ul><li>कर्मधारयः : appositioneller Tatpuruṣa, u.a.: <ul><li>उपमानपूर्वपदकर्मधारयः : विग्रहवाक्य mit इव nach erstem Glied</li><li>उपमानोत्तरपदकर्मधारयः : विग्रहवाक्य mit इव nach zweitem Glied</li><li>रूपकसमासः : विग्रहवाक्य mit एव</li><li>द्विगुसमासः : Zahlwort im Vorderglied</li></ul></li><li>नञ्तत्पुरुषः (निषेधतत्पुरुषः) : mit Verneinung a-, an- im Vorderglied</li><li>गतिसमासः : mit Präposition im Vorderglied</li><li>प्रथमातत्पुरुषः u.s.w. (siehe oben)</li></ul><h3 id="_15-7-1-einteilung-der-कर्मधारय" tabindex="-1">15.7.1. Einteilung der कर्मधारय <a class="header-anchor" href="#_15-7-1-einteilung-der-कर्मधारय" aria-label="Permalink to &quot;15.7.1. Einteilung der कर्मधारय&quot;">​</a></h3><ol><li>विशेषणपूर्वपदकर्मधारयः : Vorderglied ist Adjektiv (विशेषण)</li><li>विशेषणोभयपदकर्मधारयः : beide Glieder sind Adjektive, hierher gehören auch Adjektive, die einen Zeitablauf ausdrücken: &quot;zuerst gebadet, dann gesalbt&quot;</li><li>उपमानपूर्वपदकर्मधारयः (=  उपमासमासः): im Vorderglied Vergleich, im Hinterglied verglichene Eigenschaft: z.B. &quot;schön wie ein Lotus&quot;</li><li>उपमानोत्तरपदकर्मधारयः (=  उपमितसमासः):  Vergleich im Hinterglied</li><li>रूपकसमासः : विग्रहवाक्य mit एव nach Vorderglied (Metapher)</li><li>संभावनपूर्वपदकर्मधारयः : beide Glieder Glieder beziehen sich auf selbe Person oder Sache, z.B. कालिदासकविः = कालिदास इति कविः = &quot;der Dichter Kālidāsa&quot;</li><li>कर्मधारयः mit कु / कद् als Vorderglied: &quot;schlecht...&quot;</li><li>कर्मधारयः mit किम् als Vorderglied: Tadel</li><li>PPP + negiertes PPP: &quot;teilweise&quot;, z.B. कृताकृतम् = &quot;teilweise getan&quot;</li><li>द्विगुसमासः : Zahlwort im Vorderglied</li></ol><h2 id="_15-8-wortliste" tabindex="-1">15.8. Wortliste <a class="header-anchor" href="#_15-8-wortliste" aria-label="Permalink to &quot;15.8. Wortliste&quot;">​</a></h2><p>पुष्कल 3: herrlich, prächtig, reichlich</p><p>वा : oder (nachgestellt)</p><p>अथवा : oder (vorangestellt)</p><p>चतुर्थ 3 (f.: चतुर्थी): vierter</p><p>विद् &quot;finden&quot; 6 U विन्दति ; Pass. विद्यते ; PPP विन्न / वित्त</p><p>विद् &quot;wissen&quot; 2 P वेत्ति ; Pass. विद्यते ; PPP विदित</p><p>पत् &quot;fliegen, fallen&quot; 1 P पतति ; Pass. पत्यते ; PPP पतित</p><p>अर्ध 3: halb, m.n. Hälfte</p><p>पूजा f.: Ehrung, ehrenvoller Empfang, religiöse Verehrung (Pūjā)</p><p><img src="'+s+'" alt=""><br> Abb.: पूजा<br> A Puja ceremony held in Kakinada (కాకినాడ), Andhra Pradesh (ఆంధ్ర ప్రదేశ్), India, at the start of a seismic survey contract.<br> [Bildquelle: Wikiepdia, Public domain]</p><p>कुल n.: Herde, Menge, Geschlecht, Abstammung, Familie</p><p>इन्द्र m.: Fürst, Erster, Bester unter ; Götterkönig Indra</p><p><img src="'+o+'" alt=""><br> Abb.: इन्द्</p><blockquote><p>Indra and Sachi Riding the Divine Elephant Airavata, Folio from a Panchakalyanaka (Five Auspicious Events in the Life of Jina Rishabhanatha [Adinatha]), circa 1670-1680 Painting; Watercolor, Opaque watercolor, gold, and silver on paper, Image: 9 1/8 x 15 1/8 in. (23.18 x 38.42 cm); Sheet: 10 5/8 x 16 3/4 in. (26.99 x 42.55 cm. Made in: India, Rajasthan, Amber</p><p>[Bildquelle: Wikipedia, Public domain]</p></blockquote><p>दास m.: Sklave, Leibeigener, Diener</p><p>दासी f.: Sklavin, Leibeigene, Dienerin</p><p>काल m.: Zeit, (rechter) Zeitpunkt ; Schicksal, Tod ; Todesgott Kāla</p><p>काल 3: schwarz, blauschwarz, dunkel</p><p>पुरुष m.: Mensch, Mann, Knecht</p><p>-जन als zweites Glied von Tatpuruṣas oft Ausdruck des Plurals</p><p>स्तु 2 स्तौति ; Pass. स्तूयते ; PPP स्तुत : loben, preisen</p><p>davon:</p><blockquote><p>स्तुति f.: Lobpreis, Loblied</p><p>स्तोत्र n.: (Mittel zum Preisen =) Loblied, Hymnus</p></blockquote><p>सिंह m.: Löwe (<em>Panthera leo persica</em>)</p><p><img src="'+u+'" alt=""><br> Abb.: सिंहः  (<em>Panthera leo persica</em>)<br> [Bildquelle: Wikipedia, GNU FDLicense]</p><p>व्याघ्र m.: Tiger (<em>Panthera tigris tigris</em>) (wörtl: Gähner)</p><p><img src="'+d+'" alt=""><br> Abb.: व्याघ्रः (<em>Panthera tigris tigris</em>)<br> Bandhavgarh National Park (बांधवगढ राष्ट्रीय उद्दान)<br> [Bildquelle: U.S. Fish and Wildlife Service / Wikipedia, Public domain]</p><p>इव (nachgestellt): gleichsam, wie (in Vergleichen: व्याघ्र इव पुरुषः = &quot;ein Mann wie ein Tiger&quot;, &quot;ein tigergleicher Mann&quot;</p><p>एव (nachgestellt): betont das Vorhergehende, entspricht im Deutschen oft der Betonung, eine Art Emoticon <code>&amp;lt;!&amp;gt;, z.B. सत्यमेव जयति &quot;allein die Wahrheit siegt&quot;, &quot;gerade die Wahrheit siegt&quot;, &quot;die Wahrheit siegt&quot;</code></p><p>अरि m.: Feind (laut Thieme, Der Fremdling im Ṛgveda: ursprünglich = Fremdling)</p><blockquote><p>आर्य 3: arisch, edel ; m. Arier (Selbstbezeichnung der sanskritsprechenden alten Inder, wörtlich: Gastfreundlicher (Thieme)) ; Edler, Ehrenmann</p></blockquote><p>zu जन्</p><blockquote><p>जाति f.: Geburt, Art, Kaste (zu जाति als Kaste siehe Basham, Wonder, S. 148ff.)</p></blockquote><p>मृ 4 Ā म्रियते ; Pass. म्रियते ; PPP मृत : sterben (nach indischen Grammatikern: 6 Ā)</p><p>davon:</p><blockquote><p>मरण n.: Sterben, Tod</p><p>मृति f.: Sterben, Tod</p><p>मृत्यु m.: Tod ; personifiziert: Todesgott</p></blockquote><h2 id="ubung-1" tabindex="-1">Übung 1 <a class="header-anchor" href="#ubung-1" aria-label="Permalink to &quot;Übung 1&quot;">​</a></h2><p>Lösen Sie folgende Komposita als Tatpuruṣa in Sanskrit auf und geben Sie eine deutsche Übersetzung. Geben Sie jeweils alle Auflösungen und Übersetzungen, die Ihnen möglich erscheinen. Geben Sie auch an, um welchen Kasus und welche Zahl es sich beim Gesamtkompositum handelt.</p><p>१. देवेन्द्रस्य</p><p>२. दुःखदग्धा</p><p>३. मोक्षधर्मः</p><p>४. अन्नजातानि</p><p>५. गृहकरणम्</p><p>६. शूद्रकृतेन</p><p>७. ईश्वरपूजा</p><p>८. देवेश्वरः</p><p>९. क्षत्रिययज्ञम्</p><p>१०. वैश्यभावेन</p><p>११. देवगुरोः</p><p>१२. धनलोभः</p><p>१३. गृहदासी</p><p>१४. दुःखमोहः</p><p>१५. ग्रामेश्वरम्</p><p>१६. नगरजनाः</p><p>१७. यज्ञकालस्य</p><p>१८. देवगृहाणि</p><p>१९. देवपुत्राणाम्</p><p>२०. पश्विष्टिः</p><p>२१. स्मृत्युक्तम्</p><p>२२. गुरुगृहम्</p><p>२३. सोमयज्ञेन</p><p>२४. स्वर्गगताः</p><p>२५. सुखप्रश्नम्</p><p>२६. पशुधर्मः</p><p>२७. स्वर्गलोकः</p><p>२८. ऋषियज्ञैः</p><p>२९. तत्कालम्</p><p>३०. सत्यवदनम्</p><h2 id="ubung-2" tabindex="-1">Übung 2 <a class="header-anchor" href="#ubung-2" aria-label="Permalink to &quot;Übung 2&quot;">​</a></h2><h2 id="losen-sie-wie-bei-ubung-1-folgende-tatpurusa-auf" tabindex="-1">Lösen Sie wie bei Übung 1 folgende Tatpuruṣa auf: <a class="header-anchor" href="#losen-sie-wie-bei-ubung-1-folgende-tatpurusa-auf" aria-label="Permalink to &quot;Lösen Sie wie bei Übung 1 folgende Tatpuruṣa auf:&quot;">​</a></h2><p>१. देवतागृहम्</p><p>२. देवीस्तोत्रम्</p><p>३. ब्राह्मणगृहम्</p><p>४. वैश्यापुत्राः</p><p>५. शूद्रधर्मः</p><p>६. अग्निगृहम्</p><p>७. साधुगता</p><p>८. सत्यवचनेन</p><p>९. धर्मयज्ञानाम्</p><p>१०. सत्यधर्मः</p><p>११. अनृतवदनस्य</p><p>१२. देवीदासः</p><p>१३. द्विजदासान्</p><p>१४. अग्निदग्धम्</p><p>१५. साधुवादः</p><p>१६. बालमृगः</p><p>१७. धनसर्गः</p><p>१८. अन्नद्वेषम्</p><p>१९. देवदेवम्</p><p>२०. देवप्रश्नेन</p><p>२१. गृहजनानाम्</p><p>२२. गुरुपूजायाः</p><p>२३. गुरुगतैः</p><p>२४. स्वर्गमार्गेण</p><p>२५. नरकदेवतया</p><p>२६. गृहेश्वरः</p><p>२७. ग्रामधर्मः</p><p>२८. देवीपूजाम्</p><p>२९. देवदर्शनम्</p><p>३०. देवपादान्</p><p>३१. धनजाता</p><p>३२. बालभावेन</p><p>३३. लोकगुरोः</p><p>३४. देवपुत्रः</p><p>३५. देवमार्गम्</p><p>३६. स्वर्गसुखम्</p><p>३७. सोमसुतिः</p><p>३८. देवपूजायाः</p><p>३९. लोकधर्मेण</p><p>४०. देवजनाः</p><p>४१. पापलोकः</p><p>४२. पुण्यफलानि</p><p>४३. सत्यवादः</p><p>४४. ऋषिपुत्रः</p><p>४५. पुत्र्पुत्राः</p><p>४६. धर्मवादः</p><p>४७. देवलोकम्</p><p>४८. यज्ञेश्वरः</p><p>४९. ग्रामदेवता</p><p>५०. दुःखलोकः</p><p>५१. देवशत्रुणा</p><p>५२. क्षत्रियधर्मः</p><p>५३. द्विजेन्द्रः</p><p>५४. अग्निकृतम्</p><p>५५. साधूक्तानि</p><p>५६. ब्राह्मणभावेन</p><p>५७. देवधर्मः</p><p>५८. गृहदेवता</p><p>५९. कारुकुशीलवकृतम्</p><p>६०. द्विजातिशुश्रूषया</p><p><img src="'+m+'" alt=""><br> Abb.: ग्रामदेवता<br> Lord Virpanath @ Pasvadal village, Vadgam, Gujarat, India<br> [Bildquelle: ganuullu. --  <a href="http://www.flickr.com/photos/ganuullu/2745983608/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/ganuullu/2745983608/</a>. -- Zugriff am 2008-12-05. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="ubung-3" tabindex="-1">Übung 3 <a class="header-anchor" href="#ubung-3" aria-label="Permalink to &quot;Übung 3&quot;">​</a></h2><p>A) Übersetzen Sie das Sprichwort zu Beginn der Lektion</p><p>B) Lösen Sie folgende Tatpuruṣa auf:</p><p>१. बलकृतः</p><p>२. बालधनस्य</p><p>३. नरकाकम्</p><p>४. लोकगुरोः</p><p>५. जलेश्वरेण</p><p>६. जनपानम्</p><p>७. वाक्यसारथीन्</p><p>८. गुणवचनानि</p><p>९. मृगेश्वरैः</p><p>१०. बुद्धिकृतायाः</p><p>११. धर्मयज्ञेन</p><p>१२. यज्ञाङ्गानि</p><p>१३. गृहजनेन</p><p>१४. ग्रामलेखकाः</p><p>१५. नागदेवः</p><p>१६. पुण्यजिताभिः</p><p>१७. पापलोकम्</p><p>१८. सत्यवदनस्य</p><p>१९. दानधर्मेण</p><p>२०. सुखप्रश्नः</p><p>२१. दुःखमोहस्य</p><p>२२. सोमपात्राणि</p><p>२३. स्वर्गमार्गः</p><p>२४. कामधेन्वा</p><p>२५. वर्णधर्मः</p><p>२६. श्रुत्युदितम्</p><p><img src="'+h+'" alt=""><br> Abb.: नागदेवाः<br> Hampi (ಹಂಪೆ), Karnataka (ಕರ್ನಾಟಕ)<br> [Bildquelle: Dineshkannambadi / Wikipedia, GNU FDLicense]</p>',221)])])}const z=i(g,[["render",c]]);export{w as __pageData,z as default};
